import{_ as a,o as t,c as o,a2 as r}from"./chunks/framework.ChXBHUFc.js";const h=JSON.parse('{"title":"IMU streaming","description":"","frontmatter":{},"headers":[],"relativePath":"guide/imu-streaming.md","filePath":"guide/imu-streaming.md","lastUpdated":1782645420000}'),s={name:"guide/imu-streaming.md"};function i(n,e,c,d,l,p){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="imu-streaming" tabindex="-1">IMU streaming <a class="header-anchor" href="#imu-streaming" aria-label="Permalink to &quot;IMU streaming&quot;">​</a></h1><p>The Triki streams raw accelerometer + gyroscope over BLE once you send a multi-byte start command on RX. <strong>Verified live here.</strong></p><h2 id="start-the-stream" tabindex="-1">Start the stream <a class="header-anchor" href="#start-the-stream" aria-label="Permalink to &quot;Start the stream&quot;">​</a></h2><p>Write to RX <code>…0002</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>20 10 00 D0 07 68 00 03</span></span></code></pre></div><p>(<code>68 00</code> = 104 → ~104 Hz sample rate.)</p><h2 id="stream-format" tabindex="-1">Stream format <a class="header-anchor" href="#stream-format" aria-label="Permalink to &quot;Stream format&quot;">​</a></h2><p>The device then pushes 14-byte frames on TX <code>…0003</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>22 00 | gyroX gyroY gyroZ | accelX accelY accelZ</span></span></code></pre></div><p>Each axis is a signed int16, little-endian. Scales:</p><ul><li><strong>gyro / 14.286</strong> → deg/s — LSM6DSL ±2000 dps (70 mdps/LSB). The older <code>131.0</code> was an MPU-6050 ±250 dps value carried over from notes; it under-rotated ~9×.</li><li><strong>accel / 2048.0</strong> → g — LSM6DSL ±16 g (flat token reads +2048 = 1 g).</li></ul><p>Frames arrive in bursts at ~104 Hz (the default; the rate is selectable — see <a href="./ble-protocol#sample-rate-odr">Sample rate</a>).</p><h2 id="verification" tabindex="-1">Verification <a class="header-anchor" href="#verification" aria-label="Permalink to &quot;Verification&quot;">​</a></h2><p>Under shaking, gyro swings ±10000+, and the accel axis aligned with gravity reads ≈ +2048 (= 1 g) — decode confirmed at ~104 Hz. Reader: <code>tools/ble_imu_stream.py</code> (see <a href="./tooling">Tooling</a>).</p><p>This is sufficient to use the token as a <strong>motion controller</strong> — recover orientation via gyro + accel fusion (e.g. Madgwick AHRS).</p><blockquote><p>Note: the single-byte opcodes (<code>0x05</code> / <code>0x07</code> / <code>0x09</code> / …) are a separate diagnostic/management interface — raw IMU is NOT there; it only comes from the start-stream command above.</p></blockquote>',16)])])}const g=a(s,[["render",i]]);export{h as __pageData,g as default};
